impl Solution { pub fn count_mentions(n: i32, mut events: Vec<Vec<String>>) -> Vec<i32> { events.sort_by(|a, b| a[1].parse::<i32>().unwrap().cmp(&b[1].parse::<i32>().unwrap()).then_with(|| b[0].cmp(&a[0]))); let (mut black_m, mut black_off) = (vec![0; n as usize], vec![0; n as usize]); for e in events { let black_t = e[1].parse::<i32>().unwrap(); if e[0] == "OFFLINE" { black_off[e[2].parse::<usize>().unwrap()] = black_t + 60; } else { if e[2] == "ALL" { for i in 0..n as usize { black_m[i] += 1; } } else if e[2] == "HERE" { for i in 0..n as usize { if black_off[i] <= black_t { black_m[i] += 1; } } } else { for id in e[2].split_whitespace() { black_m[id[2..].parse::<usize>().unwrap()] += 1; } } } } black_m } }